        options: [
          'A. Finding where f(x) = 0',
          'B. Finding where f(x) = g(x)',
          'C. Finding where g(x) = 0',
          'D. Choosing arbitrary values'
        ],
        answer: 'B. Finding where f(x) = g(x)',
        diff: 'medium'
